import { GoogleGenAI, Type } from "@google/genai";
import { AIProductResult } from "../types";

export const generateHardwareSpecs = async (prompt: string): Promise<AIProductResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const systemInstruction = `
    You are MatterForce, an advanced AI Hardware Engineer. 
    Your goal is to take a natural language description of a physical product/gadget and engineering it in real-time.

    1. Analyze the user's request.
    2. Deconstruct it into technical requirements and a Bill of Materials (components).
    3. Estimate realistic costs for a "DIY Kit" (raw parts) and an "Assembled Gadget" (manufactured/labor included).
    4. Provide technical specifications.

    The output must be strictly JSON.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          productName: { type: Type.STRING, description: "A cool, technical name for the product" },
          description: { type: Type.STRING, description: "A short, professional marketing description" },
          category: { type: Type.STRING, description: "e.g., Robotics, IoT, Wearable, Power" },
          technicalSpecs: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "List of 4-6 key technical specifications (e.g., '10,000mAh Li-Po', 'IP67 Rated')"
          },
          components: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                cost: { type: Type.NUMBER },
                specs: { type: Type.STRING }
              }
            },
            description: "Bill of Materials with estimated costs in USD"
          },
          diyPrice: { type: Type.NUMBER, description: "Total cost of components + small margin" },
          assembledPrice: { type: Type.NUMBER, description: "Total cost + manufacturing/labor" },
          estimatedBuildTime: { type: Type.STRING, description: "e.g., '4 hours' or '2 weeks lead time'" }
        },
        required: ["productName", "description", "technicalSpecs", "components", "diyPrice", "assembledPrice", "estimatedBuildTime", "category"]
      }
    }
  });

  if (!response.text) {
    throw new Error("No response from AI");
  }

  try {
    return JSON.parse(response.text) as AIProductResult;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Engineering logic failed. Please try again.");
  }
};

