import React, { useState } from 'react';
import { Sparkles, Terminal, Settings, Wrench, Box, Plus, Info, CheckCircle, Loader2 } from 'lucide-react';
import { generateHardwareSpecs } from '../services/geminiService';
import { AIProductResult, CartItem } from '../types';

interface AILabProps {
  addToCart: (item: CartItem) => void;
}

const AILab: React.FC<AILabProps> = ({ addToCart }) => {
  const [prompt, setPrompt] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AIProductResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    setIsAnalyzing(true);
    setError(null);
    setResult(null);

    try {
      const data = await generateHardwareSpecs(prompt);
      setResult(data);
    } catch (err: any) {
      setError(err.message || "Failed to generate engineering data.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleAddToCart = (type: 'DIY_KIT' | 'ASSEMBLED') => {
    if (!result) return;
    const item: CartItem = {
      id: `ai-${Date.now()}`,
      name: `${result.productName} (${type === 'DIY_KIT' ? 'DIY Kit' : 'Assembled'})`,
      type,
      price: type === 'DIY_KIT' ? result.diyPrice : result.assembledPrice,
      quantity: 1,
      image: `https://picsum.photos/seed/${result.productName.replace(/\s/g,'')}/400/400`,
      details: type === 'DIY_KIT' ? 'Includes all raw components + digital schematics' : 'Professionally assembled, tested, and boxed'
    };
    addToCart(item);
  };

  return (
    <div className="min-h-screen bg-matter-dark pb-20">
      <div className="mx-auto max-w-7xl px-4 py-8 sm:px-6 lg:px-8">

        {/* Header */}
        <div className="mb-8">
          <h2 className="text-3xl font-bold tracking-tight text-white flex items-center gap-3">
            <Sparkles className="h-8 w-8 text-matter-blue" />
            AI Engineering Lab
          </h2>
          <p className="mt-2 text-slate-400">Describe your concept. The Reality Engine will design it.</p>
        </div>

        {/* Input Area */}
        <div className="rounded-2xl bg-matter-surface border border-white/5 p-1 shadow-2xl shadow-black/50">
          <div className="relative overflow-hidden rounded-xl bg-black/40">
             <textarea
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder='e.g., "A smart plant pot that waters itself based on soil moisture and has a solar panel."'
              className="w-full h-32 bg-transparent p-6 text-lg text-white placeholder-slate-500 focus:outline-none resize-none font-mono"
            />
            <div className="absolute bottom-4 right-4 flex items-center gap-4">
              {prompt.length > 0 && (
                <span className="text-xs text-slate-500 font-mono">
                  {prompt.length} chars
                </span>
              )}
              <button
                onClick={handleGenerate}
                disabled={isAnalyzing || !prompt.trim()}
                className={`flex items-center gap-2 rounded-lg px-6 py-2.5 text-sm font-semibold text-matter-dark shadow-sm transition-all
                  ${isAnalyzing || !prompt.trim() 
                    ? 'bg-slate-700 cursor-not-allowed text-slate-400' 
                    : 'bg-matter-blue hover:bg-matter-accent hover:shadow-lg hover:shadow-matter-blue/20'}`}
              >
                {isAnalyzing ? (
                  <>
                    <Loader2 className="h-4 w-4 animate-spin" />
                    Engineering...
                  </>
                ) : (
                  <>
                    Initialize Reality Engine
                    <Terminal className="h-4 w-4" />
                  </>
                )}
              </button>
            </div>
          </div>
        </div>

        {/* Error Display */}
        {error && (
            <div className="mt-6 rounded-lg bg-red-900/20 border border-red-500/50 p-4 text-red-400">
                Error: {error}
            </div>
        )}

        {/* Loading Visual */}
        {isAnalyzing && (
            <div className="mt-12 flex flex-col items-center justify-center space-y-4">
                <div className="flex gap-2">
                    <div className="h-3 w-3 rounded-full bg-matter-blue animate-bounce" style={{animationDelay: '0s'}}></div>
                    <div className="h-3 w-3 rounded-full bg-matter-blue animate-bounce" style={{animationDelay: '0.2s'}}></div>
                    <div className="h-3 w-3 rounded-full bg-matter-blue animate-bounce" style={{animationDelay: '0.4s'}}></div>
                </div>
                <p className="text-matter-blue font-mono text-sm animate-pulse">Analyzing Global Supply Chain...</p>
            </div>
        )}

        {/* Results Display */}
        {result && !isAnalyzing && (
          <div className="mt-12 animate-in fade-in slide-in-from-bottom-10 duration-700">

            {/* Project Overview */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-12">
              <div className="lg:col-span-2 space-y-6">
                <div className="flex items-start justify-between">
                    <div>
                        <h3 className="text-2xl font-bold text-white font-mono">{result.productName}</h3>
                        <span className="inline-block mt-2 rounded-full bg-slate-800 px-3 py-1 text-xs font-medium text-slate-300 ring-1 ring-inset ring-slate-700">
                            Category: {result.category}
                        </span>
                    </div>
                </div>
                <p className="text-lg text-slate-300 leading-relaxed">{result.description}</p>

                {/* Specs Grid */}
                <div className="rounded-xl bg-slate-900/50 border border-white/10 p-6">
                  <h4 className="text-sm font-semibold text-matter-blue uppercase tracking-wider mb-4 flex items-center gap-2">
                    <Settings className="w-4 h-4" /> Technical Specifications
                  </h4>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    {result.technicalSpecs.map((spec, idx) => (
                      <div key={idx} className="flex items-center gap-3 text-slate-300 font-mono text-sm">
                        <span className="h-1.5 w-1.5 rounded-full bg-matter-accent"></span>
                        {spec}
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* Visual Placeholder */}
              <div className="relative rounded-2xl overflow-hidden bg-slate-800 border border-white/10 aspect-square lg:aspect-auto">
                 <img 
                    src={`https://picsum.photos/seed/${result.productName.replace(/\s/g,'')}/600/600`}
                    alt="Blueprint"
                    className="absolute inset-0 w-full h-full object-cover opacity-60 mix-blend-overlay"
                 />
                 <div className="absolute inset-0 bg-gradient-to-t from-matter-dark to-transparent"></div>
                 <div className="absolute bottom-6 left-6 right-6">
                    <div className="text-xs font-mono text-matter-blue mb-1">VISUALIZATION RENDER</div>
                    <div className="h-1 w-full bg-slate-700 rounded-full overflow-hidden">
                        <div className="h-full bg-matter-blue w-2/3"></div>
                    </div>
                 </div>
              </div>
            </div>

            {/* Bill of Materials */}
            <div className="mb-12">
              <h4 className="text-xl font-bold text-white mb-6">Bill of Materials (BOM)</h4>
              <div className="overflow-hidden rounded-xl border border-white/10 bg-slate-900/30">
                <table className="min-w-full divide-y divide-white/10">
                  <thead className="bg-slate-900/50">
                    <tr>
                      <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase tracking-wider">Component</th>
                      <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase tracking-wider">Spec</th>
                      <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-slate-400 uppercase tracking-wider">Est. Cost</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-white/10">
                    {result.components.map((comp, idx) => (
                      <tr key={idx} className="hover:bg-white/5 transition-colors">
                        <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-white">{comp.name}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-400">{comp.specs}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-right text-matter-blue font-mono">${comp.cost.toFixed(2)}</td>
                      </tr>
