                </p>
                <div className="flex items-end justify-between border-t border-white/5 pt-6">
                  <div>
                    <p className="text-xs text-slate-500 mb-1">Total Cost</p>
                    <p className="text-3xl font-bold text-white font-mono">${result.diyPrice.toFixed(2)}</p>
                  </div>
                  <button 
                    onClick={() => handleAddToCart('DIY_KIT')}
                    className="bg-white text-matter-dark hover:bg-slate-200 px-6 py-2 rounded-lg font-semibold text-sm transition-colors flex items-center gap-2"
                  >
                    <Plus className="h-4 w-4" /> Add Kit
                  </button>
                </div>
              </div>

              {/* Assembled Card */}
              <div className="group relative overflow-hidden rounded-2xl bg-gradient-to-br from-matter-surface to-slate-900 border border-matter-blue/20 hover:border-matter-blue transition-all p-8 flex flex-col shadow-lg shadow-matter-blue/5">
                <div className="flex items-center justify-between mb-4">
                  <Box className="h-8 w-8 text-matter-blue" />
                  <span className="text-xs font-mono text-matter-blue uppercase tracking-wider">Option B</span>
                </div>
                <h3 className="text-2xl font-bold text-white mb-2">Assembled Gadget</h3>
                <p className="text-slate-400 text-sm mb-8 flex-grow">
                   Fully built by our robotics technicians, tested, and shipped in retail packaging.
                </p>
                <div className="mb-6 flex items-center gap-2 text-xs text-emerald-400 bg-emerald-400/10 w-fit px-2 py-1 rounded">
                    <CheckCircle className="w-3 h-3" />
