                </div>
                <div className="flex items-end justify-between border-t border-white/5 pt-6">
                  <div>
                    <p className="text-xs text-slate-500 mb-1">Total Cost</p>
                    <p className="text-3xl font-bold text-matter-blue font-mono">${result.assembledPrice.toFixed(2)}</p>
                  </div>
                  <button 
                    onClick={() => handleAddToCart('ASSEMBLED')}
                    className="bg-matter-blue text-matter-dark hover:bg-matter-accent px-6 py-2 rounded-lg font-semibold text-sm transition-colors flex items-center gap-2"
                  >
