export default AILab;

import React, { useState } from 'react';
import { Search, Filter, Plus, Star } from 'lucide-react';
import { MARKETPLACE_DATA } from '../constants';
import { StoreProduct, CartItem } from '../types';

interface MarketplaceProps {
  addToCart: (item: CartItem) => void;
}

const Marketplace: React.FC<MarketplaceProps> = ({ addToCart }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('All');

  const categories = ['All', ...Array.from(new Set(MARKETPLACE_DATA.map(p => p.category)))];

  const filteredProducts = MARKETPLACE_DATA.filter(product => {
    const matchesSearch = product.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          product.description.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || product.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const handleAddToCart = (product: StoreProduct) => {
    addToCart({
      id: product.id,
      name: product.name,
      type: 'STORE_ITEM',
      price: product.price,
      quantity: 1,
      image: product.image,
      details: product.category
    });
  };

  return (
    <div className="min-h-screen bg-matter-dark pb-20">
      <div className="mx-auto max-w-7xl px-4 py-8 sm:px-6 lg:px-8">

        {/* Header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
          <div>
            <h2 className="text-2xl font-bold text-white">Component Marketplace</h2>
            <p className="text-slate-400 text-sm mt-1">Industrial grade parts and pre-engineered modules.</p>
          </div>

          {/* Search Bar */}
          <div className="relative w-full md:w-96">
            <div className="pointer-events-none absolute inset-y-0 left-0 flex items-center pl-3">
              <Search className="h-4 w-4 text-slate-500" />
            </div>
            <input
              type="text"
              className="block w-full rounded-lg border border-white/10 bg-matter-surface py-2.5 pl-10 pr-3 text-sm text-white placeholder-slate-500 focus:border-matter-blue focus:outline-none focus:ring-1 focus:ring-matter-blue"
              placeholder="Search components..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {/* Categories */}
        <div className="mb-8 flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
           {categories.map((cat) => (
             <button
                key={cat}
                onClick={() => setSelectedCategory(cat)}
                className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-medium transition-colors 
                  ${selectedCategory === cat 
                    ? 'bg-matter-blue text-matter-dark' 
                    : 'bg-slate-800 text-slate-400 hover:bg-slate-700 hover:text-white'}`}
             >
                {cat}
             </button>
           ))}
        </div>

        {/* Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {filteredProducts.map((product) => (
            <div key={product.id} className="group relative flex flex-col overflow-hidden rounded-xl bg-matter-surface border border-white/5 transition-all hover:border-white/20 hover:shadow-xl hover:shadow-black/20">

              {/* Image */}
              <div className="aspect-square bg-slate-900 relative overflow-hidden">
                <img 
                  src={product.image} 
                  alt={product.name}
                  className="h-full w-full object-cover transition-transform duration-500 group-hover:scale-110 opacity-90 group-hover:opacity-100"
                />
                <div className="absolute top-2 right-2 bg-black/60 backdrop-blur px-2 py-1 rounded text-[10px] text-white font-mono">
                  {product.category}
                </div>
              </div>

              {/* Content */}
              <div className="flex flex-1 flex-col p-4">
                <div className="flex-1">
                  <h3 className="text-sm font-medium text-white line-clamp-2 mb-1">
                    {product.name}
                  </h3>
                  <div className="flex items-center gap-1 mb-2">
                     <Star className="w-3 h-3 text-yellow-500 fill-yellow-500" />
                     <span className="text-xs text-slate-500">{product.rating}</span>
                  </div>
                  <p className="text-xs text-slate-400 line-clamp-2 mb-3">
                    {product.description}
                  </p>

                  {/* Mini Specs */}
                  {product.specs && (
                    <div className="flex flex-wrap gap-1 mb-4">
                      {product.specs.slice(0, 2).map((spec, idx) => (
                        <span key={idx} className="text-[10px] bg-slate-800 text-slate-300 px-1.5 py-0.5 rounded border border-white/5">
                          {spec}
                        </span>
                      ))}
                    </div>
                  )}
                </div>

                <div className="mt-4 flex items-center justify-between border-t border-white/5 pt-4">
                  <span className="text-lg font-bold text-white font-mono">${product.price.toFixed(2)}</span>
                  <button 
                    onClick={() => handleAddToCart(product)}
                    className="rounded-lg bg-white/5 p-2 text-white hover:bg-matter-blue hover:text-matter-dark transition-colors"
                    aria-label="Add to cart"
                  >
                    <Plus className="h-5 w-5" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

        {filteredProducts.length === 0 && (
          <div className="text-center py-20">
             <Filter className="h-12 w-12 text-slate-600 mx-auto mb-4" />
             <h3 className="text-lg font-medium text-white">No products found</h3>
             <p className="text-slate-500">Try adjusting your search or category filter.</p>
          </div>
        )}

      </div>
    </div>
  );
};

export default Marketplace;

