const App = () => {
  const [currentView, setView] = useState<ViewState>('HOME');
  const [cart, setCart] = useState<CartItem[]>([]);

  const addToCart = (item: CartItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, item];
    });
    // Optional: could add toast notification here
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        return { ...item, quantity: Math.max(1, item.quantity + delta) };
      }
      return item;
    }));
  };

  const renderView = () => {
    switch (currentView) {
      case 'HOME': return <Hero setView={setView} />;
      case 'LAB': return <AILab addToCart={addToCart} />;
      case 'MARKETPLACE': return <Marketplace addToCart={addToCart} />;
      case 'CART': return <Cart cart={cart} removeFromCart={removeFromCart} updateQuantity={updateQuantity} />;
      case 'PROFILE': return <Profile />;
      default: return <Hero setView={setView} />;
    }
  };

  return (
    <div className="bg-matter-dark min-h-screen text-slate-200 font-sans selection:bg-matter-blue selection:text-matter-dark">
      <Navbar currentView={currentView} setView={setView} cart={cart} />
      <main>
        {renderView()}
      </main>
    </div>
  );
};

export default App;

