import { GoogleGenAI, Type } from "@google/genai";
import { AIProductResult } from "../types";

export const generateHardwareSpecs = async (prompt: string): Promise<AIProductResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const systemInstruction = `
    You are MatterForce, India's advanced Hardware Intelligence Engine.
    Your goal is to engineer physical products from natural language descriptions for the Indian maker market.

    1. Analyze the request and deconstruct it into a BOM (Bill of Materials).
    2. PERFORM A VIRTUAL "MARKET SWEEP": Estimate realistic prices in Indian Rupees (INR) based on vendors like Robu.in, Amazon.in, Flipkart, and Lajpat Rai Market (Delhi).
    3. Select specific, available components (e.g., "Arduino Uno R3", "HC-SR04").
    4. Generate a logical, step-by-step assembly guide for a user building this by hand.

    The output must be strictly JSON.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          productName: { type: Type.STRING, description: "Technical product name" },
          description: { type: Type.STRING, description: "Professional description" },
          category: { type: Type.STRING, description: "e.g., IoT, Robotics, Home Automation" },
          technicalSpecs: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Key technical specs (e.g., '5V Operating Voltage', 'Zigbee Protocol')"
          },
          components: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                cost: { type: Type.NUMBER, description: "Cost in INR" },
                specs: { type: Type.STRING },
                vendor: { type: Type.STRING, description: "Best vendor source, e.g. 'Robu.in', 'Amazon.in'" }
              }
            },
            description: "Bill of Materials with estimated INR costs"
          },
          diyPrice: { type: Type.NUMBER, description: "Total component cost in INR" },
          assembledPrice: { type: Type.NUMBER, description: "Total cost + labor/manufacturing fee in INR" },
          estimatedBuildTime: { type: Type.STRING, description: "Time to build" },
          assemblySteps: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Step-by-step wiring/assembly instructions (e.g., 'Connect VCC to 5V pin on Arduino')"
          }
        },
        required: ["productName", "description", "technicalSpecs", "components", "diyPrice", "assembledPrice", "estimatedBuildTime", "category", "assemblySteps"]
      }
    }
  });

  if (!response.text) {
    throw new Error("No response from AI");
  }

  try {
    return JSON.parse(response.text) as AIProductResult;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Engineering logic failed. Please try again.");
  }
};

