export default Cart;

import React, { useState, useEffect } from 'react';
import { Trash2, ShoppingBag, ArrowRight, Truck, Plus, Minus, CreditCard, Banknote, CheckCircle, FileText, X, BookOpen, PenTool, Share2, Link as LinkIcon, Copy } from 'lucide-react';
import { CartItem } from '../types';

interface CartProps {
  cart: CartItem[];
  removeFromCart: (id: string) => void;
  updateQuantity: (id: string, delta: number) => void;
}

const Cart: React.FC<CartProps> = ({ cart, removeFromCart, updateQuantity }) => {
  // Initialize step from localStorage or default to 'REVIEW'
  const [step, setStep] = useState<'REVIEW' | 'ADDRESS' | 'PAYMENT' | 'SUCCESS'>(() => {
    try {
      const savedStep = localStorage.getItem('mf_cart_step');
      return (savedStep as 'REVIEW' | 'ADDRESS' | 'PAYMENT' | 'SUCCESS') || 'REVIEW';
    } catch {
      return 'REVIEW';
    }
  });

  const [selectedBlueprint, setSelectedBlueprint] = useState<{name: string, steps: string[]} | null>(null);
  const [sharingItem, setSharingItem] = useState<CartItem | null>(null);
  const [copied, setCopied] = useState(false);

  // Initialize address from localStorage or default
  const [address, setAddress] = useState(() => {
    try {
      const savedAddress = localStorage.getItem('mf_cart_address');
      return savedAddress ? JSON.parse(savedAddress) : {
        houseNo: '',
        street: '',
        landmark: '',
        city: '',
        state: '',
        pincode: ''
      };
    } catch {
      return {
        houseNo: '',
        street: '',
        landmark: '',
        city: '',
        state: '',
        pincode: ''
      };
    }
  });

  // Persist step changes
  useEffect(() => {
    localStorage.setItem('mf_cart_step', step);
  }, [step]);

  // Persist address changes
  useEffect(() => {
    localStorage.setItem('mf_cart_address', JSON.stringify(address));
  }, [address]);

  // Reset copied state when modal closes or item changes
  useEffect(() => {
    setCopied(false);
  }, [sharingItem]);

  const subtotal = cart.reduce((acc, item) => acc + item.price * item.quantity, 0);
  const shipping = subtotal > 1500 ? 0 : 99; // Free shipping over 1500 INR
  const total = subtotal + shipping;

  const handleCheckout = () => {
    if (step === 'REVIEW') setStep('ADDRESS');
    else if (step === 'ADDRESS') {
      // Basic validation
      if(!address.pincode || !address.city) return;
      setStep('PAYMENT');
    }
    else if (step === 'PAYMENT') setStep('SUCCESS');
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  if (cart.length === 0 && step !== 'SUCCESS') {
    return (
      <div className="flex min-h-[60vh] flex-col items-center justify-center p-8 text-center bg-matter-dark font-sans">
        <div className="rounded-full bg-matter-surface border border-matter-border p-6 mb-4">
          <ShoppingBag className="h-12 w-12 text-slate-600" />
        </div>
        <h2 className="text-2xl font-bold text-white font-mono uppercase">Supply Chain Empty</h2>
        <p className="mt-2 text-slate-400">Initialize a project in The Foundry or source parts in The Bazaar.</p>
      </div>
    );
  }

  if (step === 'SUCCESS') {
    return (
        <div className="flex min-h-[60vh] flex-col items-center justify-center p-8 text-center bg-matter-dark font-sans">
            <div className="rounded-full bg-green-900/20 p-6 mb-6 border border-green-500/50">
                <CheckCircle className="h-16 w-16 text-green-500" />
            </div>
            <h2 className="text-3xl font-bold text-white font-mono uppercase mb-2">Order Confirmed</h2>
            <p className="text-slate-400 mb-8 max-w-md">
                Your Hardware Intelligence Order <span className="text-matter-orange font-mono">#MF-IN-{Math.floor(Math.random() * 10000)}</span> has been dispatched to the logistics network.
            </p>
            <div className="bg-matter-surface p-6 rounded border border-matter-border text-left w-full max-w-md">
                <div className="flex justify-between mb-2">
                    <span className="text-slate-500 text-sm">Estimated Delivery</span>
                    <span className="text-white font-mono">3-5 Business Days</span>
                </div>
                <div className="flex justify-between">
                    <span className="text-slate-500 text-sm">Carrier</span>
                    <span className="text-white font-mono">BlueDart Express</span>
                </div>
            </div>

            {/* Added a button to reset for demo purposes if they want to start over */}
            <button 
                onClick={() => {
                    setStep('REVIEW');
                    localStorage.setItem('mf_cart_step', 'REVIEW');
                    // In a real app, this would also clear the cart in parent
                }}
                className="mt-8 text-sm text-slate-500 hover:text-white underline underline-offset-4"
            >
                Start New Order
            </button>
        </div>
    )
  }

  return (
